using System;
using System.Collections.Generic;
using GTA;
using GTA.Native;
using ModProject.LiveStudio;

namespace ModProject
{
    public class Mod : Script
    {
        private LiveStudioClient _client;
        private readonly Dictionary<string, DateTime> _cooldowns = new Dictionary<string, DateTime>();
        private readonly List<Vehicle> _spawnedVehicles = new List<Vehicle>();
        private const int PingCooldownMs = 3000;
        private const int RoseCooldownMs = 10000;
        private const int MaxArmor = 100;
        private const int ArmorAmount = 25;

        public Mod()
        {
            Tick += OnTick;
            Aborted += OnAborted;

            _client = new LiveStudioClient(
                onEvent: HandleEvent,
                onLog: msg => MainThreadDispatcher.Enqueue(() => GTA.UI.Notification.Show("~y~" + msg))
            );
            _client.Start();
        }

        private void OnTick(object sender, EventArgs e)
        {
            MainThreadDispatcher.DrainOnTick();
        }

        private void OnAborted(object sender, EventArgs e)
        {
            CleanupSpawnedVehicles();
            _client?.Stop();
        }

        private void HandleEvent(LiveStudioEvent evt)
        {
            if (evt is ChatEvent chat && chat.Message?.ToLowerInvariant().Trim() == "ping")
            {
                if (!IsOnCooldown("ping"))
                {
                    SetCooldown("ping", PingCooldownMs);
                    MainThreadDispatcher.Enqueue(() =>
                    {
                        Game.Player.Character.Armor = Math.Min(Game.Player.Character.Armor + ArmorAmount, MaxArmor);
                        GTA.UI.Screen.ShowSubtitle("Ping! Armor +25", 3000);
                    });
                }
            }
            else if (evt is GiftEvent gift && gift.GiftId == 5655)
            {
                if (!IsOnCooldown("rose"))
                {
                    SetCooldown("rose", RoseCooldownMs);
                    MainThreadDispatcher.Enqueue(() => SpawnPoliceCar());
                }
            }
        }

        private void SpawnPoliceCar()
        {
            Ped player = Game.Player.Character;
            if (player == null || !player.Exists()) return;

            Vector3 pos = player.Position + player.ForwardVector * 4.0f;
            float heading = player.Heading;

            Model model = new Model("police");
            if (!model.IsValid || !model.IsVehicle) return;

            Vehicle vehicle = World.CreateVehicle(model, pos, heading);
            if (vehicle == null || !vehicle.Exists()) return;

            vehicle.IsInvincible = true;
            vehicle.CanBeVisiblyDamaged = false;
            vehicle.IsEngineRunning = true;
            vehicle.PlaceOnGround();
            _spawnedVehicles.Add(vehicle);
        }

        private bool IsOnCooldown(string key)
        {
            if (_cooldowns.TryGetValue(key, out DateTime cooldownEnd))
            {
                return DateTime.UtcNow < cooldownEnd;
            }
            return false;
        }

        private void SetCooldown(string key, int milliseconds)
        {
            _cooldowns[key] = DateTime.UtcNow.AddMilliseconds(milliseconds);
        }

        private void CleanupSpawnedVehicles()
        {
            foreach (Vehicle vehicle in _spawnedVehicles)
            {
                if (vehicle != null && vehicle.Exists())
                {
                    vehicle.Delete();
                }
            }
            _spawnedVehicles.Clear();
        }
    }
}
